export const fields = (typeName) => schemas[typeName] || [];

export class BufferMessage {
  static schema = schemas.BufferMessage;
  constructor(init = {}) {
    this.SequenceNo = init.SequenceNo;
    this.TargetTime = init.TargetTime;
  }

  toMsgpackMap() {
    const out = new Map();
    if (this.SequenceNo !== undefined) out.set(100, this.SequenceNo);
    if (this.TargetTime !== undefined) out.set(101, this.TargetTime);
    return out;
  }

  encode() {
    return packNative(this.toMsgpackMap());
  }

  decode(bytes) {
    const raw = unpackNative(bytes);
    if (hasKey(raw, 100)) this.SequenceNo = getKey(raw, 100);
    if (hasKey(raw, 101)) this.TargetTime = getKey(raw, 101);
    return this;
  }
}

